import{c as n,Z as l,Q as o,j as i,g as e,n as r,o as c,m as s}from"./chunks/framework.qjzPVSkb.js";const C=JSON.parse('{"title":"Function Calling","description":"让 LLM 输出结构化 JSON 来调用外部函数或 API，实现 AI 与外部系统的交互能力","frontmatter":{"title":"Function Calling","description":"让 LLM 输出结构化 JSON 来调用外部函数或 API，实现 AI 与外部系统的交互能力","difficulty":"intermediate"},"headers":[],"relativePath":"terms/function-calling.md","filePath":"terms/function-calling.md"}'),u={name:"terms/function-calling.md"};function g(d,t,h,m,p,f){const a=l("DifficultyBadge");return o(),i("div",null,[t[0]||(t[0]=e("h1",{id:"function-calling",tabindex:"-1"},[r("Function Calling "),e("a",{class:"header-anchor",href:"#function-calling","aria-label":'Permalink to "Function Calling"'},"​")],-1)),c(a,{level:"intermediate"}),t[1]||(t[1]=s('<h2 id="一句话解释" tabindex="-1">一句话解释 <a class="header-anchor" href="#一句话解释" aria-label="Permalink to &quot;一句话解释&quot;">​</a></h2><p>Function Calling（函数调用）是一种让 LLM <strong>输出结构化 JSON 参数来调用外部工具或 API</strong> 的能力。它不是 LLM 真的执行了函数，而是模型根据用户意图决定&quot;该调用哪个函数、传什么参数&quot;，由你的程序负责实际执行并将结果返回给模型。</p><h2 id="通俗类比" tabindex="-1">通俗类比 <a class="header-anchor" href="#通俗类比" aria-label="Permalink to &quot;通俗类比&quot;">​</a></h2><p>假设你让 AI 助手&quot;查一下北京明天天气&quot;。模型本身不知道天气，但它知道自己有个&quot;查天气&quot;的工具可用。于是它输出：&quot;好，我现在需要一个工具——查天气（城市=北京，日期=明天）&quot;。你的程序收到这个指令后，真的去调天气 API 拿到数据（&quot;北京明天 25°C，晴&quot;），把结果塞回给模型。模型再给你一个自然的回答：&quot;北京明天晴天，气温 25°C，适合出行。&quot; 整个过程中，模型扮演的是&quot;翻译官+决策者&quot;的角色，把自然语言请求翻译为 API 调用。</p><h2 id="技术定义" tabindex="-1">技术定义 <a class="header-anchor" href="#技术定义" aria-label="Permalink to &quot;技术定义&quot;">​</a></h2><p>Function Calling 的标准流程：</p><ol><li><strong>定义函数列表</strong>：开发者将可用的函数列表（函数名、描述、参数 schema）作为 Prompt 的一部分传给模型</li><li><strong>模型决策</strong>：当用户输入匹配某个函数的用途时，模型返回一个包含函数名和 JSON 参数的响应，而不是普通的文本回答</li><li><strong>程序执行</strong>：开发者的代码解析模型输出的 JSON，实际调用对应的函数/API</li><li><strong>结果回传</strong>：将函数返回结果再次发给模型，模型基于结果生成最终的自然语言回答</li></ol><p>目前主流 LLM（GPT-4、Claude、DeepSeek 等）都原生支持 Function Calling，且通常以 <strong>OpenAI 兼容格式</strong> 提供接口。参数 Schema 一般使用 JSON Schema 定义。</p><p>与 <a href="/ai-knowledge/terms/agent.html">Agent</a> 的关系：Function Calling 是 Agent 的<strong>原子能力</strong>——Agent 通过多次 Function Calling 的循环（观察→决策→调用→观察→…）来实现复杂任务的自主完成。</p><h2 id="关联术语" tabindex="-1">关联术语 <a class="header-anchor" href="#关联术语" aria-label="Permalink to &quot;关联术语&quot;">​</a></h2><ul><li><a href="/ai-knowledge/terms/agent.html">Agent</a> —— Agent 依赖 Function Calling 与外部世界交互</li><li><a href="/ai-knowledge/terms/prompt.html">Prompt</a> —— Function Calling 的本质是让 Prompt 包含工具定义并引导模型输出结构化 JSON</li><li><a href="/ai-knowledge/terms/llm.html">大语言模型 (LLM)</a> —— 支持 Function Calling 是现代 LLM 的标配能力</li></ul><h2 id="延伸阅读" tabindex="-1">延伸阅读 <a class="header-anchor" href="#延伸阅读" aria-label="Permalink to &quot;延伸阅读&quot;">​</a></h2><ul><li>OpenAI Function Calling 文档：<a href="https://platform.openai.com/docs/guides/function-calling" target="_blank" rel="noreferrer">Function calling guide</a></li><li>Anthropic Tool Use 文档：<a href="https://docs.anthropic.com/en/docs/build-with-claude/tool-use" target="_blank" rel="noreferrer">Tool use with Claude</a></li><li><a href="/ai-knowledge/dev/tool-calling.html">Tool Calling 实战</a> — API 调用完整示例</li></ul>',13))])}const _=n(u,[["render",g]]);export{C as __pageData,_ as default};
